import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [tab, setTab] = useState('users');
  const [themeTrigger, setThemeTrigger] = useState(false);

  useEffect(() => {
    API.get('/admin/users').then(res => setUsers(res.data));
    API.get('/admin/posts').then(res => setPosts(res.data));
    API.get('/admin/comments').then(res => setComments(res.data));
  }, []);

  useEffect(() => {
    const handleThemeChange = () => setThemeTrigger(prev => !prev);
    window.addEventListener("storage", handleThemeChange);
    return () => window.removeEventListener("storage", handleThemeChange);
  }, []);

  const toggleStatus = async (id) => {
    const { data } = await API.put(`/admin/users/${id}/status`);
    setUsers(users.map(u => (u._id === id ? data.user : u)));
  };

  const removePost = async (id) => {
    if (!window.confirm("Permanently delete this post? This cannot be undone.")) return;
    try {
      await API.delete(`/posts/${id}`); 
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Error deleting post.");
    }
  };

  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(comments.filter(c => c._id !== id));
  };

  const viewPost = (postId) => {
    // FIXED: Changed from /post/ to /posts/ to match your App.js route
    navigate(`/posts/${postId}`);
  };

  const isDark = document.body.classList.contains('dark-mode');

  // BABY PINK & DARK GREEN THEME COLORS
  const colors = {
    babyPink: '#FCE4EC',
    deepPink: '#F8BBD0',
    darkGreen: '#1B5E20', // Forest/Dark Green
    lightGreen: '#E8F5E9',
    white: '#FFFFFF',
    textDark: '#0A2610'
  };

  const styles = {
    page: {
      backgroundColor: isDark ? '#1a0510' : colors.babyPink,
      minHeight: '100vh',
      padding: '40px 20px',
      fontFamily: '"Segoe UI", Tahoma, sans-serif',
      color: isDark ? '#f5d6e6' : colors.textDark,
    },
    container: {
      maxWidth: '1100px',
      margin: '0 auto',
      backgroundColor: isDark ? '#2e091e' : colors.white,
      padding: '40px',
      borderRadius: '30px',
      boxShadow: '0 10px 40px rgba(27, 94, 32, 0.15)',
      border: `2px solid ${colors.deepPink}`
    },
    heading: {
      fontSize: '32px',
      textAlign: 'center',
      marginBottom: '30px',
      fontWeight: '800',
      color: colors.darkGreen,
      textTransform: 'uppercase',
      letterSpacing: '1px'
    },
    tabs: {
      display: 'flex',
      justifyContent: 'center',
      gap: '12px',
      marginBottom: '35px',
    },
    tabButton: {
      padding: '12px 28px',
      borderRadius: '15px',
      border: `2px solid ${colors.darkGreen}`,
      cursor: 'pointer',
      fontWeight: 'bold',
      backgroundColor: 'transparent',
      color: colors.darkGreen,
      transition: 'all 0.3s ease',
    },
    activeTab: {
      backgroundColor: colors.darkGreen,
      color: colors.babyPink,
      boxShadow: '0 4px 15px rgba(27, 94, 32, 0.3)'
    },
    tableWrapper: {
      overflowX: 'auto',
      borderRadius: '15px',
      border: `1px solid ${colors.deepPink}`
    },
    table: {
      width: '100%',
      borderCollapse: 'collapse',
      backgroundColor: isDark ? '#3a253a' : colors.white,
    },
    th: {
      padding: '18px 15px',
      backgroundColor: colors.darkGreen,
      color: colors.babyPink,
      textAlign: 'left',
      fontSize: '14px',
    },
    td: {
      padding: '15px',
      borderBottom: `1px solid ${colors.deepPink}`,
      color: isDark ? '#f5d6e6' : colors.textDark,
      fontSize: '15px',
    },
    actionCell: {
      display: 'flex',
      gap: '10px',
      flexWrap: 'nowrap'
    },
    btnView: {
      padding: '8px 16px',
      borderRadius: '10px',
      border: 'none',
      backgroundColor: colors.darkGreen,
      color: colors.white,
      cursor: 'pointer',
      fontWeight: '600',
      display: 'flex',
      alignItems: 'center',
      gap: '5px'
    },
    btnDelete: {
      padding: '8px 16px',
      borderRadius: '10px',
      border: `1.5px solid #ff4d6d`,
      backgroundColor: 'transparent',
      color: '#ff4d6d',
      cursor: 'pointer',
      fontWeight: '600',
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Admin Portal</h2>

        <div style={styles.tabs}>
          {['users', 'posts', 'comments'].map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              style={{ ...styles.tabButton, ...(tab === t ? styles.activeTab : {}) }}
            >
              {t.toUpperCase()} ({t === 'users' ? users.length : t === 'posts' ? posts.length : comments.length})
            </button>
          ))}
        </div>

        <div style={styles.tableWrapper}>
          <table style={styles.table}>
            <thead>
              {tab === 'users' && (
                <tr>
                  <th style={styles.th}>Username</th>
                  <th style={styles.th}>Email</th>
                  <th style={styles.th}>Status</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
              {tab === 'posts' && (
                <tr>
                  <th style={styles.th}>Title</th>
                  <th style={styles.th}>Author</th>
                  <th style={styles.th}>Actions</th>
                </tr>
              )}
              {tab === 'comments' && (
                <tr>
                  <th style={styles.th}>User</th>
                  <th style={styles.th}>Comment</th>
                  <th style={styles.th}>Action</th>
                </tr>
              )}
            </thead>
            <tbody>
              {tab === 'users' && users.map(u => (
                <tr key={u._id}>
                  <td style={styles.td}><strong>{u.name}</strong></td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.status}</td>
                  <td style={styles.td}>
                    <button style={styles.btnView} onClick={() => toggleStatus(u._id)}>
                      {u.status === 'active' ? 'Ban User' : 'Unban User'}
                    </button>
                  </td>
                </tr>
              ))}

              {tab === 'posts' && posts.map(p => (
                <tr key={p._id}>
                  <td style={styles.td}>{p.title}</td>
                  <td style={styles.td}>{p.author?.name || 'Unknown'}</td>
                  <td style={styles.td}>
                    <div style={styles.actionCell}>
                      <button style={styles.btnView} onClick={() => viewPost(p._id)}>
                        👁 View
                      </button>
                      <button style={styles.btnDelete} onClick={() => removePost(p._id)}>
                        🗑 Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}

              {tab === 'comments' && comments.map(c => (
                <tr key={c._id}>
                  <td style={styles.td}><strong>{c.author?.name}</strong></td>
                  <td style={styles.td}>{c.body}</td>
                  <td style={styles.td}>
                    <button style={styles.btnDelete} onClick={() => deleteComment(c._id)}>
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default AdminPage;
